#!/usr/bin/env node
import fs from "node:fs";
import path from "node:path";
import { execFileSync } from "node:child_process";

const repoRoot = process.cwd();
const agentsDir = path.join(repoRoot, "agents_self_contained");
const outputDir = path.join(repoRoot, "agents");

const chapterFiles = fs
  .readdirSync(agentsDir)
  .filter((name) => /^s\d+.*\.ts$/.test(name) || name === "s_full.ts")
  .sort((a, b) => a.localeCompare(b));

if (chapterFiles.length === 0) {
  throw new Error("No chapter files found in agents_self_contained/");
}

// Rebuild output from scratch so old generated files never linger.
fs.rmSync(outputDir, { recursive: true, force: true });
fs.mkdirSync(outputDir, { recursive: true });

for (const file of chapterFiles) {
  const entry = path.join("agents_self_contained", file);
  const outfile = path.join("agents", file);

  execFileSync(
    "npx",
    [
      "esbuild",
      entry,
      "--bundle",
      "--platform=node",
      "--format=esm",
      "--target=node20",
      `--outfile=${outfile}`,
      "--external:@anthropic-ai/sdk",
      "--external:dotenv",
    ],
    {
      cwd: repoRoot,
      stdio: "inherit",
    }
  );

  const built = fs.readFileSync(path.join(repoRoot, outfile), "utf8");
  const header = [
    "// @ts-nocheck",
    "// AUTO-GENERATED by scripts/generate-self-contained-agents.mjs",
    `// Source chapter: ${entry}`,
    "// Tree-shaken bundle: chapter wiring + only used runtime code.",
    "",
  ].join("\n");
  fs.writeFileSync(path.join(repoRoot, outfile), `${header}${built}`, "utf8");
}

console.log(
  `Generated ${chapterFiles.length} progressive self-contained chapters in agents/`
);
